export interface SeedResult {
  phaseRequirementsSeeded: number;
  ragPatternsSeeded: number;
}

@Injectable()
export class PhaseRequirementsSeeder {
  private readonly logger = new Logger(PhaseRequirementsSeeder.name);

  constructor(@Inject(DATABASE_SERVICE) private readonly db: IDatabaseService) {}

  async seed(): Promise<DataProcessResult<SeedResult>> {
    try {
      let phaseRequirementsSeeded = 0;
      let ragPatternsSeeded = 0;

      // Seed phase requirement documents — DNA-8: storeDocument first
      for (const phase of FLOW37_PHASES) {
        const doc: Record<string, unknown> = {
          id: `FLOW-37-${phase.phaseId}`,
          flowId: 'FLOW-37',
          phaseId: phase.phaseId,
          requirements: phase.requirements,
          status: 'NOT_STARTED',
          connectionType: 'FLOW_SCOPED',
          tenantId: MASTER_TENANT_ID,
          createdAt: new Date().toISOString(),
        };
        const result = await this.db.storeDocument(
          PHASE_REQ_INDEX,
          doc,
          `FLOW-37-${phase.phaseId}`,
        );
        if (result.isSuccess) {
          phaseRequirementsSeeded++;
        } else {
          this.logger.warn(
            `PhaseRequirementsSeeder: failed to seed ${phase.phaseId}: ${result.errorMessage ?? 'unknown'}`,
          );
        }
      }

      // Seed RAG patterns — DNA-8: storeDocument, no emit needed for seeds
      for (const seed of FLOW37_RAG_SEEDS) {
        const result = await this.db.storeDocument(
          RAG_INDEX,
          { ...seed, createdAt: new Date().toISOString() } as Record<string, unknown>,
          seed.patternId,
        );
        if (result.isSuccess) {
          ragPatternsSeeded++;
        } else {
          this.logger.warn(
            `PhaseRequirementsSeeder: failed to seed ${seed.patternId}: ${result.errorMessage ?? 'unknown'}`,
          );
        }
      }

      this.logger.log(
        `PhaseRequirementsSeeder: complete — phaseRequirements=${phaseRequirementsSeeded} ragPatterns=${ragPatternsSeeded}`,
      );
      return DataProcessResult.success({ phaseRequirementsSeeded, ragPatternsSeeded });
    } catch (err) {
      return DataProcessResult.failure(
        'SEEDER_ERROR',
        `PhaseRequirementsSeeder threw: ${String(err)}`,
      );
    }
  }
}
